<template>
  <div class="space-y-5">
    <div class="flex items-center justify-between gap-4">
      <p class="text-[12.5px] text-ink-faint">
        Job별로 자동 실행 여부와 주기를 설정합니다. 저장 즉시 반영되며(재배포 불필요), 이미 실행 중인 배치에는 영향을 주지 않습니다.
      </p>
      <button @click="refresh" class="btn btn--ghost btn--sm flex-none"><Icon name="rotate" size="sm"/>새로고침</button>
    </div>

    <div v-for="(jobs, domain) in itemsByDomain" :key="domain" class="panel">
      <div class="panel__head"><h2 class="flex items-center gap-2"><Icon :name="domainIcon(domain)" class="text-ink-muted"/>{{ domain }}</h2></div>
      <div class="space-y-3">
        <div v-for="item in jobs" :key="item.jobName" class="p-3 rounded-[10px] border border-line">
          <div class="flex items-start justify-between gap-4 flex-wrap">
            <div class="min-w-[14rem]">
              <div class="font-semibold text-[13.5px]">{{ item.jobName }}</div>
              <div class="text-[12px] text-ink-faint">{{ item.description }}</div>
            </div>

            <label class="flex items-center gap-2 text-[13px] cursor-pointer select-none">
              <input type="checkbox" v-model="edits[item.jobName].enabled" class="w-4 h-4 accent-brand" />
              실행
            </label>
          </div>

          <div class="mt-3 flex flex-wrap items-center gap-2.5 text-[13px]">
            <select v-model="edits[item.jobName].mode" class="field">
              <option value="interval">N분마다</option>
              <option value="daily">특정 시각(요일)</option>
              <option value="custom">직접입력(cron)</option>
            </select>

            <template v-if="edits[item.jobName].mode === 'interval'">
              <input type="number" min="1" max="59" v-model.number="edits[item.jobName].minutes" class="field w-20" />
              <span class="text-ink-faint">분마다</span>
            </template>

            <template v-else-if="edits[item.jobName].mode === 'daily'">
              <input type="number" min="0" max="23" v-model.number="edits[item.jobName].hour" class="field w-16" />
              <span class="text-ink-faint">시</span>
              <input type="number" min="0" max="59" v-model.number="edits[item.jobName].minute" class="field w-16" />
              <span class="text-ink-faint">분</span>
              <div class="flex items-center gap-1">
                <button v-for="d in DAY_ORDER" :key="d" @click="toggleDay(item.jobName, d)"
                        class="w-7 h-7 rounded-[7px] text-xs border transition-colors"
                        :class="edits[item.jobName].days.includes(d)
                          ? 'bg-brand text-white border-brand'
                          : 'border-line hover:bg-neutral-tint'">
                  {{ DAY_LABELS[d] }}
                </button>
              </div>
              <span class="text-[12px] text-ink-faint">(선택 없음 = 매일)</span>
            </template>

            <template v-else>
              <input v-model="edits[item.jobName].raw" placeholder="0 */10 * * * *" class="field w-56 font-mono text-xs" />
              <span class="text-[12px] text-ink-faint">초 분 시 일 월 요일</span>
            </template>

            <button @click="save(item)" :disabled="saving[item.jobName]" class="btn btn--primary btn--sm ml-auto">저장</button>
          </div>

          <div class="mt-2 text-[12px] text-ink-faint flex items-center gap-3">
            <span>cron: <code class="font-mono">{{ previewCron(item.jobName) }}</code></span>
            <span v-if="item.enabled && item.nextFireTime">다음 실행: {{ fmt(item.nextFireTime) }}</span>
            <span v-else>비활성</span>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, reactive, computed } from 'vue'
import api from '../services/api'
import Icon from '../components/Icon.vue'
import { fmt } from '../utils/format'
import { domainIcon } from '../utils/domain'
import { DAY_ORDER, DAY_LABELS, buildIntervalCron, buildDailyCron, parseCron } from '../utils/cron'
import { useUiStore } from '../stores/uiStore'

const ui = useUiStore()

const items = ref([])
const edits = reactive({})
const saving = reactive({})

const itemsByDomain = computed(() => {
  const groups = {}
  items.value.forEach((item) => {
    ;(groups[item.domain] = groups[item.domain] || []).push(item)
  })
  return groups
})

function toEditState(item) {
  return { enabled: item.enabled, ...parseCron(item.cronExpression) }
}

function toggleDay(jobName, day) {
  const days = edits[jobName].days
  const idx = days.indexOf(day)
  if (idx >= 0) days.splice(idx, 1)
  else days.push(day)
}

function cronFor(edit) {
  if (edit.mode === 'interval') return buildIntervalCron(edit.minutes)
  if (edit.mode === 'daily') return buildDailyCron(edit.hour, edit.minute, edit.days)
  return edit.raw
}

function previewCron(jobName) {
  const edit = edits[jobName]
  return edit ? cronFor(edit) : ''
}

const refresh = async () => {
  try {
    const [schedRes, jobsRes] = await Promise.all([api.listSchedules(), api.listJobs()])
    const descByName = Object.fromEntries(jobsRes.data.map((j) => [j.name, j.description]))
    items.value = schedRes.data.map((item) => ({ ...item, description: descByName[item.jobName] || '' }))
    items.value.forEach((item) => {
      if (!edits[item.jobName]) edits[item.jobName] = toEditState(item)
    })
  } catch (e) {
    ui.toast('error', e.userMessage)
  }
}

const save = async (item) => {
  const edit = edits[item.jobName]
  const cronExpression = cronFor(edit)
  saving[item.jobName] = true
  try {
    const res = await api.updateSchedule(item.jobName, { enabled: edit.enabled, cronExpression })
    Object.assign(item, res.data)
    ui.toast('success', `${item.jobName} 스케줄 저장됨${item.enabled ? ` (다음 실행: ${fmt(item.nextFireTime)})` : ''}`)
  } catch (e) {
    ui.toast('error', e.userMessage)
  } finally {
    saving[item.jobName] = false
  }
}

refresh()
</script>
