<template>
  <button
    @click="toggleDark()"
    class="w-14 h-8 flex items-center rounded-full transition-colors duration-300 relative flex-none"
    :class="isDark ? 'bg-ink' : 'bg-neutral-tint'"
    aria-label="다크모드 토글"
  >
    <span
      class="w-6 h-6 flex items-center justify-center rounded-full bg-surface shadow transform transition-transform duration-300 z-10"
      :class="isDark ? 'translate-x-7' : 'translate-x-1'"
    >
      <Icon :name="isDark ? 'moon' : 'sun'" size="sm" :class="isDark ? 'text-brand' : 'text-warning'"/>
    </span>
  </button>
</template>

<script setup>
import { useDark, useToggle } from '@vueuse/core'
import Icon from './Icon.vue'

const isDark = useDark()
const toggleDark = useToggle(isDark)
</script>