<template>
  <div class="space-y-5">
    <div class="flex items-center justify-between">
      <p class="text-[12.5px] text-ink-faint">최근 24시간 · {{ asOf }} 기준</p>
      <button @click="refresh" class="btn btn--ghost btn--sm"><Icon name="rotate" size="sm"/>새로고침</button>
    </div>

    <!-- KPI -->
    <section class="grid grid-cols-2 md:grid-cols-4 gap-3.5">
      <article class="panel !p-4 flex flex-col gap-2.5">
        <span class="w-8 h-8 rounded-[9px] bg-neutral-tint text-neutral flex items-center justify-center"><Icon name="grid"/></span>
        <div class="text-[28px] font-extrabold font-mono tracking-tight">{{ summary.total }}</div>
        <div class="text-[12.5px] text-ink-muted font-medium">오늘 실행</div>
      </article>
      <article class="panel !p-4 flex flex-col gap-2.5">
        <span class="w-8 h-8 rounded-[9px] bg-success-tint text-success flex items-center justify-center"><Icon name="check"/></span>
        <div class="text-[28px] font-extrabold font-mono tracking-tight">{{ summary.completed }}</div>
        <div class="text-[12.5px] text-ink-muted font-medium">성공</div>
      </article>
      <article class="panel !p-4 flex flex-col gap-2.5" :class="{ '!border-danger/40': summary.failed > 0 }">
        <span class="w-8 h-8 rounded-[9px] bg-danger-tint text-danger flex items-center justify-center"><Icon name="x"/></span>
        <div class="text-[28px] font-extrabold font-mono tracking-tight">{{ summary.failed }}</div>
        <div class="text-[12.5px] text-ink-muted font-medium">실패</div>
      </article>
      <article class="panel !p-4 flex flex-col gap-2.5">
        <span class="w-8 h-8 rounded-[9px] bg-info-tint text-info flex items-center justify-center"><Icon name="rotate" :spin="running.length > 0"/></span>
        <div class="text-[28px] font-extrabold font-mono tracking-tight">{{ running.length }}</div>
        <div class="text-[12.5px] text-ink-muted font-medium">실행중</div>
      </article>
    </section>

    <!-- Attention + Live -->
    <section class="grid grid-cols-1 lg:grid-cols-[1.5fr_1fr] gap-3.5 items-start">
      <div class="panel">
        <div class="panel__head">
          <h2>지금 확인이 필요합니다</h2>
          <span v-if="failed.length" class="pill pill--danger">{{ failed.length }}건</span>
        </div>

        <ul v-if="failed.length" class="divide-y divide-line -mx-1">
          <li v-for="exec in failed" :key="exec.executionId" class="relative flex items-start gap-3 py-3 pl-4 pr-1">
            <span class="absolute left-0 top-1.5 bottom-1.5 w-[3px] rounded bg-danger"></span>
            <Icon name="x" class="text-danger mt-0.5"/>
            <div class="flex-1 min-w-0 flex flex-col gap-1">
              <div class="flex items-center gap-2 text-[13.5px] flex-wrap">
                <span class="job-tag"><Icon :name="domainIcon(exec.domain)" size="sm"/>{{ exec.domain }}</span>
                <b>{{ exec.jobName }}</b>
                <span class="font-mono text-ink-faint">#{{ exec.executionId }}</span>
              </div>
              <div class="text-[12.5px] text-ink-muted font-mono">{{ fmt(exec.startTime) }}</div>
            </div>
            <div class="flex gap-1.5 flex-none">
              <button @click="selectedExecutionId = exec.executionId" class="btn btn--ghost btn--sm">상세</button>
              <button @click="actions.restart(exec)" class="btn btn--primary btn--sm"><Icon name="rotate" size="sm"/>재실행</button>
            </div>
          </li>
        </ul>
        <div v-else class="empty-state">
          <Icon name="check" size="lg" class="text-success"/>
          <span>실패한 실행이 없습니다</span>
        </div>
      </div>

      <div class="flex flex-col gap-3.5">
        <div class="panel">
          <div class="panel__head">
            <h2>실행중</h2>
            <span v-if="running.length" class="pill pill--info">5초 갱신</span>
          </div>
          <ul v-if="running.length" class="flex flex-col gap-3">
            <li v-for="exec in running" :key="exec.executionId" class="flex items-center justify-between gap-3 text-[13px]">
              <div class="flex items-center gap-2 min-w-0">
                <Icon name="rotate" size="sm" spin class="text-info flex-none"/>
                <span class="job-tag flex-none"><Icon :name="domainIcon(exec.domain)" size="sm"/>{{ exec.domain }}</span>
                <b class="truncate">{{ exec.jobName }}</b>
                <span class="font-mono text-ink-faint flex-none">{{ fmtElapsed(exec.startTime) }}</span>
              </div>
              <button @click="actions.stop(exec)" class="btn btn--ghost btn--sm btn--danger-text flex-none">
                <Icon name="stop" size="sm"/>중지
              </button>
            </li>
          </ul>
          <div v-else class="empty-state !py-6">
            <Icon name="inbox"/>
            <span>실행중인 배치가 없습니다</span>
          </div>
        </div>

        <div class="panel">
          <div class="panel__head"><h2>도메인별 현황</h2><span class="text-[12px] text-ink-faint">24h</span></div>
          <ul v-if="Object.keys(summary.byDomain).length" class="flex flex-col gap-2">
            <li v-for="(counts, domain) in summary.byDomain" :key="domain"
                class="flex items-center justify-between gap-2 py-1.5 text-[13px]">
              <span class="job-tag"><Icon :name="domainIcon(domain)" size="sm"/>{{ domain }}</span>
              <div class="flex items-center gap-1.5">
                <span class="text-ink-faint font-mono text-[12px]">{{ counts.total }}건</span>
                <span v-if="counts.failed > 0" class="pill pill--danger">실패 {{ counts.failed }}</span>
                <span v-if="counts.running > 0" class="pill pill--info">실행중 {{ counts.running }}</span>
                <Icon v-if="!counts.failed && !counts.running" name="check" size="sm" class="text-success"/>
              </div>
            </li>
          </ul>
          <div v-else class="empty-state !py-6">
            <Icon name="inbox"/>
            <span>최근 24시간 실행 이력이 없습니다</span>
          </div>
        </div>
      </div>
    </section>

    <ExecutionDetail :execution-id="selectedExecutionId" @close="selectedExecutionId = null"/>
  </div>
</template>

<script setup>
import { ref } from 'vue'
import dayjs from 'dayjs'
import api from '../services/api'
import Icon from '../components/Icon.vue'
import ExecutionDetail from '../components/ExecutionDetail.vue'
import { fmt, fmtElapsed } from '../utils/format'
import { domainIcon } from '../utils/domain'
import { usePolling } from '../composables/usePolling'
import { useExecutionActions } from '../composables/useExecutionActions'
import { useUiStore } from '../stores/uiStore'

const ui = useUiStore()

const summary = ref({ total: 0, completed: 0, failed: 0, running: 0, byDomain: {} })
const running = ref([])
const failed = ref([])
const selectedExecutionId = ref(null)
const asOf = ref('')

const refresh = async () => {
  try {
    const [summaryRes, runningRes, failedRes] = await Promise.all([
      api.getSummary(24),
      api.listRunning(),
      api.searchExecutions({
        status: 'FAILED',
        from: dayjs().subtract(1, 'day').format('YYYY-MM-DD'),
        size: 10,
      }),
    ])
    summary.value = summaryRes.data
    running.value = runningRes.data
    failed.value = failedRes.data.content
    asOf.value = dayjs().format('YYYY-MM-DD (ddd) HH:mm')
  } catch (e) {
    ui.toast('error', e.userMessage)
  }
}

// 실행중 있으면 5초, 없으면 30초 폴링
const { reschedule } = usePolling(refresh, () => (running.value.length > 0 ? 5000 : 30000))

const actions = useExecutionActions(async () => {
  await refresh()
  reschedule()
})
</script>
