import dayjs from 'dayjs'

export const RUNNING_STATUSES = ['STARTING', 'STARTED', 'STOPPING']

export const isRunning = (status) => RUNNING_STATUSES.includes(status)
export const canRestart = (status) => status === 'FAILED' || status === 'STOPPED'

export const fmt = (dt) => (dt ? dayjs(dt).format('YYYY-MM-DD HH:mm:ss') : '-')
export const fmtTime = (dt) => (dt ? dayjs(dt).format('HH:mm:ss') : '-')

export const fmtDuration = (ms) => {
  if (ms == null || ms < 0) return '-'
  if (ms < 1000) return `${ms}ms`
  const s = Math.floor(ms / 1000)
  if (s < 60) return `${s}s`
  return `${Math.floor(s / 60)}m ${s % 60}s`
}

/** 실행 시작 시각부터의 경과시간 (실행중 표시용) */
export const fmtElapsed = (startTime) => {
  if (!startTime) return '-'
  return fmtDuration(Date.now() - dayjs(startTime).valueOf())
}

