import axios from 'axios'
// X-API-KEY 인증 임시 비활성화 — 재활성화 시 아래 주석 해제
// import { useApiKeyStore } from '../stores/apiKeyStore'

// 상대경로 고정:
// - dev: vite server.proxy 가 /api → 백엔드로 전달
// - 운영: 빌드 산출물이 mony_batch static 으로 서빙되므로 동일 오리진 (프록시 불필요)
const api = axios.create({
  baseURL: '/api/batch',
  timeout: 15000,
})

// 요청마다 저장된 API 키를 X-API-KEY 헤더로 첨부
// api.interceptors.request.use((config) => {
//   const key = useApiKeyStore().key
//   if (key) config.headers['X-API-KEY'] = key
//   return config
// })

// 에러 정규화: 백엔드 { code, message } 응답을 e.code / e.userMessage 로 노출
api.interceptors.response.use(
  (res) => res,
  (err) => {
    const data = err.response?.data
    err.code = data?.code || err.code || 'NETWORK_ERROR'
    err.userMessage = data?.message || err.message || '요청 처리 중 오류가 발생했습니다'
    // 401(키 불일치)이면 저장된 키를 지우고 재입력 프롬프트를 띄운다
    // if (err.response?.status === 401) {
    //   const keyStore = useApiKeyStore()
    //   keyStore.clear()
    //   keyStore.openPrompt()
    // }
    return Promise.reject(err)
  },
)

export default {
  /** Job 목록 + 최근 실행 요약 */
  listJobs() { return api.get('/jobs') },
  /** 실행 이력 검색: { jobName, status, from, to, page, size } */
  searchExecutions(params) { return api.get('/executions', { params }) },
  /** 실행중 목록 (폴링용) */
  listRunning() { return api.get('/executions/running') },
  /** 실행 상세: { execution, params, steps } */
  getExecution(id) { return api.get(`/executions/${id}`) },
  /** KPI 요약 */
  getSummary(hours = 24) { return api.get('/summary', { params: { hours } }) },
  launchJob(jobName, params) { return api.post(`/jobs/${encodeURIComponent(jobName)}/launch`, params || {}) },
  stopExecution(id) { return api.post(`/executions/${id}/stop`) },
  restartExecution(id) { return api.post(`/executions/${id}/restart`) },
  /** 도메인 로그 tail + Kibana 딥링크: { domain, file, lines, kibanaUrl } */
  fetchLogs(id, lines = 300) { return api.get(`/executions/${id}/logs`, { params: { lines } }) },
  /** 파라미터 명세: [{ key, label, format, defaultValue, required }] */
  getParamSpecs(jobName) { return api.get(`/jobs/${encodeURIComponent(jobName)}/param-specs`) },

  /** 스케줄 목록: [{ jobName, domain, enabled, cronExpression, nextFireTime }] */
  listSchedules() { return api.get('/schedules') },
  updateSchedule(jobName, body) { return api.put(`/schedules/${encodeURIComponent(jobName)}`, body) },
  previewCron(cronExpression) { return api.get('/schedules/preview', { params: { cronExpression } }) },
}
