<template>
  <div class="space-y-5">
    <div class="flex items-center justify-end">
      <button @click="refresh" class="btn btn--ghost btn--sm"><Icon name="rotate" size="sm"/>새로고침</button>
    </div>

    <div v-for="(domainJobs, domain) in jobsByDomain" :key="domain" class="panel">
      <div class="panel__head">
        <h2 class="flex items-center gap-2"><Icon :name="domainIcon(domain)" class="text-ink-muted"/>{{ domain }}</h2>
      </div>

      <div class="table-scroll">
        <table class="data-table">
          <thead>
            <tr>
              <th>Job</th>
              <th>설명</th>
              <th>최근 실행</th>
              <th></th>
            </tr>
          </thead>
          <tbody>
            <tr v-for="job in domainJobs" :key="job.name">
              <td class="font-semibold">{{ job.name }}</td>
              <td class="text-ink-muted">{{ job.description }}</td>
              <td>
                <div v-if="job.lastExecution" class="flex items-center gap-2">
                  <StatusBadge :status="job.lastExecution.status"/>
                  <span class="text-ink-faint font-mono text-[12.5px]">
                    {{ fmt(job.lastExecution.startTime) }} · {{ fmtDuration(job.lastExecution.durationMs) }}
                  </span>
                </div>
                <span v-else class="text-ink-faint">실행 이력 없음</span>
              </td>
              <td class="text-right">
                <div class="inline-flex gap-1.5">
                  <button @click="goHistory(job.name)" class="btn btn--ghost btn--sm"><Icon name="clock" size="sm"/>이력</button>
                  <button @click="launchTarget = job" :disabled="isRunning(job.lastExecution?.status)"
                          class="btn btn--primary btn--sm">
                    <Icon name="play" size="sm"/>실행
                  </button>
                </div>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <div v-if="!Object.keys(jobsByDomain).length" class="panel empty-state">
      <Icon name="inbox"/>
      <span>등록된 Job이 없습니다</span>
    </div>

    <LaunchModal :job="launchTarget" @close="launchTarget = null" @launched="refresh"/>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'
import { useRouter } from 'vue-router'
import api from '../services/api'
import Icon from '../components/Icon.vue'
import StatusBadge from '../components/StatusBadge.vue'
import LaunchModal from '../components/LaunchModal.vue'
import { fmt, fmtDuration, isRunning } from '../utils/format'
import { domainIcon } from '../utils/domain'
import { usePolling } from '../composables/usePolling'
import { useUiStore } from '../stores/uiStore'

const router = useRouter()
const ui = useUiStore()

const jobs = ref([])
const launchTarget = ref(null)

const jobsByDomain = computed(() => {
  const groups = {}
  jobs.value.forEach((job) => {
    ;(groups[job.domain] = groups[job.domain] || []).push(job)
  })
  return groups
})

const refresh = async () => {
  try {
    jobs.value = (await api.listJobs()).data
  } catch (e) {
    ui.toast('error', e.userMessage)
  }
}

// 실행중인 Job이 있으면 5초, 아니면 30초마다 최근 실행 상태 갱신
usePolling(refresh, () =>
  (jobs.value.some((j) => isRunning(j.lastExecution?.status)) ? 5000 : 30000))

const goHistory = (jobName) => {
  router.push({ path: '/executions', query: { jobName } })
}
</script>
