<template>
  <div v-if="detail" class="panel space-y-5">
    <div class="flex items-center justify-between gap-4">
      <h3 class="text-[15px] font-bold flex items-center gap-2 flex-wrap">
        실행 상세 · {{ detail.execution.jobName }} <span class="font-mono text-ink-faint">#{{ detail.execution.executionId }}</span>
        <StatusBadge :status="detail.execution.status"/>
      </h3>
      <button @click="$emit('close')" class="icon-btn icon-btn--ghost"><Icon name="close" size="sm"/></button>
    </div>

    <div class="flex flex-wrap gap-x-5 gap-y-1 text-[12.5px] text-ink-muted font-mono">
      <span>시작 {{ fmt(detail.execution.startTime) }}</span>
      <span>종료 {{ fmt(detail.execution.endTime) }}</span>
      <span>소요 {{ fmtDuration(detail.execution.durationMs) }}</span>
      <span>Exit {{ detail.execution.exitCode || '-' }}</span>
    </div>

    <!-- 실행 파라미터 -->
    <div v-if="detail.params.length">
      <h4 class="text-[12px] font-bold text-ink-faint uppercase tracking-wide mb-1.5">실행 파라미터</h4>
      <div class="flex flex-wrap gap-1.5">
        <span v-for="p in detail.params" :key="p.name" class="job-tag font-mono">{{ p.name }}={{ p.value }}</span>
      </div>
    </div>

    <!-- 종료 메시지 (실패 시 스택트레이스) -->
    <div v-if="detail.execution.exitMessage">
      <h4 class="text-[12px] font-bold text-ink-faint uppercase tracking-wide mb-1.5">Exit Message</h4>
      <pre class="p-3 rounded-[10px] bg-danger-tint text-danger text-xs whitespace-pre-wrap max-h-48 overflow-auto font-mono">{{ detail.execution.exitMessage }}</pre>
    </div>

    <!-- 로그 (도메인 로그 파일 tail) -->
    <div>
      <div class="flex items-center gap-2 mb-1.5">
        <h4 class="text-[12px] font-bold text-ink-faint uppercase tracking-wide">로그</h4>
        <button v-if="!logData" @click="loadLogs" class="btn btn--ghost btn--sm">로그 보기</button>
        <template v-else>
          <span class="text-[12px] text-ink-faint font-mono">{{ logData.file }} · {{ logData.lines.length }}줄</span>
          <button @click="loadLogs" class="icon-btn icon-btn--sm icon-btn--ghost"><Icon name="rotate" size="sm"/></button>
          <a v-if="logData.kibanaUrl" :href="logData.kibanaUrl" target="_blank" rel="noopener" class="btn btn--ghost btn--sm">
            <Icon name="external" size="sm"/>Kibana에서 열기
          </a>
        </template>
      </div>
      <pre v-if="logData"
           class="p-3 rounded-[10px] bg-gray-900 text-green-300 text-xs whitespace-pre-wrap max-h-80 overflow-auto font-mono">{{ logData.lines.join('\n') || '(해당 Job의 로그가 없습니다)' }}</pre>
    </div>

    <!-- Step 테이블 -->
    <div class="table-scroll rounded-[10px] border border-line">
      <table class="data-table">
        <thead>
          <tr>
            <th>Step</th>
            <th>상태</th>
            <th class="num">Read/Write</th>
            <th class="num">Commit</th>
            <th class="num">Filter</th>
            <th class="num">Skip(R/W/P)</th>
            <th class="num">Rollback</th>
            <th class="num">소요시간</th>
            <th>종료 메시지</th>
          </tr>
        </thead>
        <tbody>
          <tr v-for="step in detail.steps" :key="step.stepExecutionId">
            <td class="font-semibold">{{ step.stepName }}</td>
            <td><StatusBadge :status="step.status"/></td>
            <td class="num font-mono">{{ step.readCount }}/{{ step.writeCount }}</td>
            <td class="num font-mono">{{ step.commitCount }}</td>
            <td class="num font-mono">{{ step.filterCount }}</td>
            <td class="num font-mono">{{ step.readSkipCount }}/{{ step.writeSkipCount }}/{{ step.processSkipCount }}</td>
            <td class="num font-mono">{{ step.rollbackCount }}</td>
            <td class="num font-mono">{{ fmtDuration(step.durationMs) }}</td>
            <td class="text-left truncate max-w-xs text-ink-muted">[{{ step.exitCode || 'N/A' }}] {{ step.exitMessage || '' }}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</template>

<script setup>
import { ref, watch } from 'vue'
import api from '../services/api'
import Icon from './Icon.vue'
import StatusBadge from './StatusBadge.vue'
import { fmt, fmtDuration } from '../utils/format'
import { useUiStore } from '../stores/uiStore'

const props = defineProps({ executionId: { type: [Number, String], default: null } })
defineEmits(['close'])

const ui = useUiStore()
const detail = ref(null)
const logData = ref(null)

watch(() => props.executionId, async (id) => {
  logData.value = null
  if (id == null) {
    detail.value = null
    return
  }
  try {
    detail.value = (await api.getExecution(id)).data
  } catch (e) {
    detail.value = null
    ui.toast('error', e.userMessage)
  }
}, { immediate: true })

const loadLogs = async () => {
  try {
    logData.value = (await api.fetchLogs(props.executionId)).data
  } catch (e) {
    ui.toast('error', e.userMessage)
  }
}
</script>
