import api from '../services/api'
import { useUiStore } from '../stores/uiStore'

/**
 * 실행 중지/재시작 공통 액션 (확인창 + 토스트 + 완료 후 갱신).
 * afterChange: 조작 성공 후 호출되는 갱신 콜백
 */
export function useExecutionActions(afterChange) {
  const ui = useUiStore()

  const stop = async (exec) => {
    const ok = await ui.confirm('실행 중지', `${exec.jobName} #${exec.executionId} 을(를) 중지할까요?`)
    if (!ok) return
    try {
      const res = await api.stopExecution(exec.executionId)
      ui.toast('success', res.data.message)
      await afterChange()
    } catch (e) {
      ui.toast('error', e.userMessage)
    }
  }

  const restart = async (exec) => {
    const ok = await ui.confirm('재시작', `${exec.jobName} #${exec.executionId} 을(를) 같은 파라미터로 재시작할까요?`)
    if (!ok) return
    try {
      const res = await api.restartExecution(exec.executionId)
      ui.toast('success', `재시작 접수됨 (새 executionId=${res.data.executionId})`)
      await afterChange()
    } catch (e) {
      ui.toast('error', e.userMessage)
    }
  }

  return { stop, restart }
}
