// Spring CronTrigger 형식(초 분 시 일 월 요일)의 최소 빌더/파서.
// 화면은 "인터벌"과 "특정 시각(요일)" 두 가지 흔한 패턴만 폼으로 지원하고,
// 그 외 패턴은 원본 cron을 그대로 보여주는 "직접입력" 모드로 표시한다.

export const DAY_ORDER = ['MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT', 'SUN']
export const DAY_LABELS = { MON: '월', TUE: '화', WED: '수', THU: '목', FRI: '금', SAT: '토', SUN: '일' }

export function buildIntervalCron(minutes) {
  const m = Math.min(Math.max(parseInt(minutes, 10) || 1, 1), 59)
  return `0 */${m} * * * *`
}

export function buildDailyCron(hour, minute, days) {
  const h = Math.min(Math.max(parseInt(hour, 10) || 0, 0), 23)
  const mi = Math.min(Math.max(parseInt(minute, 10) || 0, 0), 59)
  const dow = (!days || days.length === 0 || days.length === 7) ? '*' : days.join(',')
  return `0 ${mi} ${h} * * ${dow}`
}

/** 저장된 cron을 폼 상태로 최대한 복원. 매칭 안 되면 custom(직접입력) 모드. */
export function parseCron(cron) {
  const base = { mode: 'daily', minutes: 10, hour: 9, minute: 0, days: [], raw: cron || '' }
  if (!cron) return base

  let m = cron.match(/^0 \*\/(\d{1,2}) \* \* \* \*$/)
  if (m) return { ...base, mode: 'interval', minutes: Number(m[1]) }

  m = cron.match(/^0 (\d{1,2}) (\d{1,2}) \* \* (\*|[A-Z,]+)$/)
  if (m) {
    const days = m[3] === '*' ? [] : m[3].split(',')
    return { ...base, mode: 'daily', minute: Number(m[1]), hour: Number(m[2]), days }
  }

  return { ...base, mode: 'custom' }
}
