<template>
  <span class="pill" :class="`pill--${meta.tone}`">
    <Icon :name="meta.icon" size="sm" :spin="running"/>
    {{ meta.label }}
  </span>
</template>

<script setup>
import { computed } from 'vue'
import Icon from './Icon.vue'

const props = defineProps({ status: { type: String, default: null } })

const RUNNING = ['STARTING', 'STARTED', 'STOPPING']
const running = computed(() => RUNNING.includes(props.status))

const META = {
  COMPLETED: { tone: 'success', icon: 'check', label: '성공' },
  FAILED: { tone: 'danger', icon: 'x', label: '실패' },
  STOPPED: { tone: 'neutral', icon: 'stop', label: '중지됨' },
  ABANDONED: { tone: 'danger', icon: 'warn', label: '중단됨' },
}

const meta = computed(() => {
  if (running.value) return { tone: 'info', icon: 'rotate', label: props.status === 'STOPPING' ? '중지중' : '실행중' }
  return META[props.status] || { tone: 'neutral', icon: 'warn', label: props.status || 'N/A' }
})
</script>
