<template>
  <div v-if="job" class="fixed inset-0 bg-black/50 flex items-center justify-center z-30 p-4"
       @click.self="$emit('close')">
    <div class="panel w-full max-w-sm">
      <h3 class="text-[15px] font-bold mb-1 flex items-center gap-2"><Icon name="play"/>Job 실행 · {{ job.name }}</h3>
      <p class="text-[12.5px] text-ink-faint mb-4">{{ job.description }}</p>

      <div v-for="spec in paramSpecs" :key="spec.key" class="mb-3">
        <label class="block text-[13px] mb-1">
          {{ spec.label }}
          <span v-if="spec.required" class="text-danger">*</span>
          <span class="text-[11.5px] text-ink-faint ml-1 font-mono">({{ spec.key }})</span>
        </label>
        <input v-model="jobParams[spec.key]" type="text" :placeholder="spec.format" class="field w-full"
               :class="{ '!border-danger': invalidKeys.includes(spec.key) }" />
        <p v-if="invalidKeys.includes(spec.key)" class="text-[11.5px] text-danger mt-1">필수 입력입니다</p>
      </div>
      <p v-if="paramSpecs.length === 0" class="text-[13px] text-ink-faint mb-2">필수 파라미터 없음</p>

      <div class="mt-4 flex justify-end gap-2">
        <button @click="$emit('close')" class="btn btn--ghost">취소</button>
        <button @click="launch" :disabled="launching" class="btn btn--primary">
          <Icon name="play" size="sm"/>실행
        </button>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, watch } from 'vue'
import api from '../services/api'
import Icon from './Icon.vue'
import { useUiStore } from '../stores/uiStore'

const props = defineProps({ job: { type: Object, default: null } })
const emit = defineEmits(['close', 'launched'])

const ui = useUiStore()
const paramSpecs = ref([])
const jobParams = ref({})
const invalidKeys = ref([])
const launching = ref(false)

watch(() => props.job, async (job) => {
  paramSpecs.value = []
  jobParams.value = {}
  invalidKeys.value = []
  if (!job) return
  try {
    const res = await api.getParamSpecs(job.name)
    paramSpecs.value = res.data
    res.data.forEach((spec) => { jobParams.value[spec.key] = spec.defaultValue || '' })
  } catch (e) {
    ui.toast('error', e.userMessage)
    emit('close')
  }
}, { immediate: true })

const launch = async () => {
  // required=값 필수. 키는 스펙에 있는 것 전부(빈 문자열 포함) 전송되어 validator를 통과한다
  invalidKeys.value = paramSpecs.value
    .filter((s) => s.required && !jobParams.value[s.key])
    .map((s) => s.key)
  if (invalidKeys.value.length) return

  const paramText = Object.entries(jobParams.value)
    .map(([k, v]) => `${k}=${v || '(빈값)'}`)
    .join(', ') || '(없음)'
  const ok = await ui.confirm('Job 실행', `${props.job.name} 을(를) 실행할까요?\n파라미터: ${paramText}`)
  if (!ok) return

  launching.value = true
  try {
    const res = await api.launchJob(props.job.name, jobParams.value)
    ui.toast('success', `실행 접수됨 (executionId=${res.data.executionId})`)
    emit('launched')
    emit('close')
  } catch (e) {
    ui.toast('error', e.userMessage)
  } finally {
    launching.value = false
  }
}
</script>
