<template>
  <div class="min-h-screen flex bg-canvas font-sans text-ink">
    <IconSprite/>

    <aside class="w-56 flex-none bg-surface border-r border-line flex flex-col gap-7 p-3.5">
      <div class="flex items-center gap-2 px-1.5">
        <span class="w-7 h-7 rounded-lg bg-brand text-white flex items-center justify-center flex-none">
          <Icon name="pulse" size="sm"/>
        </span>
        <span class="font-semibold tracking-tight text-[15px]">배치 <b class="font-extrabold text-brand">콘솔</b></span>
      </div>

      <nav class="flex flex-col gap-0.5">
        <router-link v-for="tab in tabs" :key="tab.path" :to="tab.path"
                     class="flex items-center gap-2.5 px-2.5 py-2 rounded-[7px] text-[13.5px] font-medium transition-colors"
                     :class="isActive(tab.path) ? 'bg-brand-tint text-brand-strong font-bold' : 'text-ink-muted hover:bg-neutral-tint hover:text-ink'">
          <Icon :name="tab.icon"/>{{ tab.label }}
        </router-link>
      </nav>

      <div class="mt-auto flex items-center px-1.5">
        <span class="text-[10.5px] font-extrabold tracking-wider px-1.5 py-0.5 rounded"
              :class="envBadge.class">{{ envBadge.label }}</span>
      </div>
    </aside>

    <div class="flex-1 min-w-0 flex flex-col">
      <header class="flex items-center justify-between gap-4 px-7 py-3.5 border-b border-line bg-surface">
        <h1 class="text-[15px] font-bold">{{ pageTitle }}</h1>
        <div class="flex items-center gap-2">
          <!-- X-API-KEY 인증 임시 비활성화 — 재활성화 시 아래 버튼/ApiKeyModal 주석 해제
          <button @click="apiKeyStore.openPrompt()" title="API 키 설정" class="icon-btn">
            <Icon name="key"/>
          </button>
          -->
          <DarkModeToggle />
        </div>
      </header>
      <main class="p-7 max-w-[1240px] w-full mx-auto">
        <router-view />
      </main>
    </div>

    <Toast />
    <ConfirmDialog />
