<script setup>
import { computed } from 'vue'
import { useRoute } from 'vue-router'
import IconSprite from './components/icons/IconSprite.vue'
import Icon from './components/Icon.vue'
import DarkModeToggle from './components/DarkModeToggle.vue'
import Toast from './components/Toast.vue'
import ConfirmDialog from './components/ConfirmDialog.vue'
// X-API-KEY 인증 임시 비활성화 — 재활성화 시 아래 주석 해제
// import ApiKeyModal from './components/ApiKeyModal.vue'
// import { useApiKeyStore } from './stores/apiKeyStore'

const route = useRoute()
// const apiKeyStore = useApiKeyStore()
const tabs = [
  { path: '/', label: '대시보드', icon: 'grid' },
  { path: '/jobs', label: 'Job 관리', icon: 'play' },
  { path: '/executions', label: '실행 이력', icon: 'clock' },
  { path: '/schedules', label: '스케줄', icon: 'calendar' },
]
const isActive = (path) => (path === '/' ? route.path === '/' : route.path.startsWith(path))
const pageTitle = computed(() => tabs.find((t) => isActive(t.path))?.label || '배치 콘솔')

const ENV_BADGES = {
  production: { label: 'PROD', class: 'bg-danger-tint text-danger' },
  development: { label: 'DEV', class: 'bg-warning-tint text-warning' },
  devlocal: { label: 'LOCAL', class: 'bg-info-tint text-info' },
}
const envBadge = computed(() => ENV_BADGES[import.meta.env.MODE] || ENV_BADGES.devlocal)

// 최초 진입 시 키가 없으면 입력 프롬프트 노출 (서버가 키를 요구하지 않으면 비워두고 닫아도 무방)
