import { defineStore } from 'pinia'

let toastSeq = 0

/** 토스트 알림 + 확인 다이얼로그 전역 상태 */
export const useUiStore = defineStore('ui', {
  state: () => ({
    toasts: [], // { id, type: 'success'|'error'|'info', message }
    confirmState: null, // { title, message, resolve }
  }),
  actions: {
    toast(type, message, timeout = 4000) {
      const id = ++toastSeq
      this.toasts.push({ id, type, message })
      setTimeout(() => this.dismiss(id), timeout)
    },
    dismiss(id) {
      this.toasts = this.toasts.filter((t) => t.id !== id)
    },
    /** 사용: const ok = await ui.confirm('제목', '내용') */
    confirm(title, message) {
      return new Promise((resolve) => {
        this.confirmState = { title, message, resolve }
      })
    },
    answerConfirm(ok) {
      if (this.confirmState) {
        this.confirmState.resolve(ok)
        this.confirmState = null
      }
    },
  },
})
