import { onMounted, onUnmounted } from 'vue'

/**
 * 적응형 폴링: intervalFn()이 반환한 간격(ms)마다 refreshFn 실행.
 * - intervalFn이 null 반환 시 폴링 중단 (수동 새로고침만)
 * - 탭이 숨겨지면 중단, 다시 보이면 즉시 갱신 후 재개
 * 반환된 reschedule()은 데이터 변경 직후 간격을 재계산할 때 호출.
 */
export function usePolling(refreshFn, intervalFn) {
  let timer = null

  const schedule = () => {
    clearTimeout(timer)
    const ms = intervalFn()
    if (ms != null && !document.hidden) {
      timer = setTimeout(async () => {
        await refreshFn()
        schedule()
      }, ms)
    }
  }

  const onVisibility = async () => {
    if (document.hidden) {
      clearTimeout(timer)
    } else {
      await refreshFn()
      schedule()
    }
  }

  onMounted(async () => {
    await refreshFn()
    schedule()
    document.addEventListener('visibilitychange', onVisibility)
  })

  onUnmounted(() => {
    clearTimeout(timer)
    document.removeEventListener('visibilitychange', onVisibility)
  })

  return { reschedule: schedule }
}
