<template>
  <div class="space-y-5">
    <div class="flex items-center justify-end gap-3 text-[13px] text-ink-muted">
      <span v-if="runningCount > 0" class="pill pill--info">실행중 {{ runningCount }}건 · 5초 갱신</span>
      <button @click="refresh" class="btn btn--ghost btn--sm"><Icon name="rotate" size="sm"/>새로고침</button>
    </div>

    <div class="panel">
      <!-- 필터 -->
      <div class="flex flex-wrap items-center gap-2 mb-4">
        <select v-model="filters.jobName" @change="applyFilters" class="field">
          <option value="">전체 Job</option>
          <option v-for="job in jobs" :key="job.name" :value="job.name">{{ job.name }}</option>
        </select>

        <div class="flex items-center gap-1.5">
          <button v-for="opt in STATUS_OPTIONS" :key="opt.value"
                  @click="filters.status = opt.value; applyFilters()"
                  class="chip" :class="{ 'chip--active': filters.status === opt.value }">
            {{ opt.label }}
          </button>
        </div>

        <input v-model="filters.from" type="date" @change="applyFilters" class="field"/>
        <span class="text-ink-faint text-sm">~</span>
        <input v-model="filters.to" type="date" @change="applyFilters" class="field"/>

        <button v-if="hasFilter" @click="clearFilters" class="btn btn--ghost btn--sm ml-auto">
          <Icon name="close" size="sm"/>필터 초기화
        </button>
      </div>

      <div class="table-scroll">
        <table class="data-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Job</th>
              <th>상태</th>
              <th>시작</th>
              <th>종료</th>
              <th class="num">소요시간</th>
              <th></th>
            </tr>
          </thead>
          <tbody>
            <tr v-for="exec in executions.content" :key="exec.executionId">
              <td class="font-mono text-ink-faint">#{{ exec.executionId }}</td>
              <td>
                <div class="flex items-center gap-2">
                  <span class="job-tag"><Icon :name="domainIcon(exec.domain)" size="sm"/>{{ exec.domain }}</span>
                  <b>{{ exec.jobName }}</b>
                </div>
              </td>
              <td><StatusBadge :status="exec.status"/></td>
              <td class="font-mono text-[12.5px]">{{ fmt(exec.startTime) }}</td>
              <td class="font-mono text-[12.5px]">{{ fmt(exec.endTime) }}</td>
              <td class="num font-mono">{{ fmtDuration(exec.durationMs) }}</td>
              <td class="text-right">
                <div class="inline-flex gap-1.5">
                  <button @click="selectedExecutionId = exec.executionId" class="btn btn--ghost btn--sm">상세</button>
                  <button v-if="isRunning(exec.status)" @click="actions.stop(exec)" class="btn btn--ghost btn--sm btn--danger-text">
                    <Icon name="stop" size="sm"/>중지
                  </button>
                  <button v-if="canRestart(exec.status)" @click="actions.restart(exec)" class="btn btn--primary btn--sm">
                    <Icon name="rotate" size="sm"/>재실행
                  </button>
                </div>
              </td>
            </tr>
          </tbody>
        </table>
        <div v-if="!executions.content.length" class="empty-state">
          <Icon name="inbox"/>
          <span>조건에 맞는 실행 이력이 없습니다</span>
        </div>
      </div>

      <!-- 페이징 -->
      <div class="flex items-center justify-between mt-4 text-[13px] text-ink-muted">
        <span>총 {{ executions.totalElements }}건</span>
        <div class="flex items-center gap-2">
          <button :disabled="page <= 0" @click="page--; refresh()" class="icon-btn icon-btn--sm">
            <Icon name="chevron-left" size="sm"/>
          </button>
          <span class="font-mono text-[12.5px]">{{ page + 1 }} / {{ Math.max(executions.totalPages, 1) }}</span>
          <button :disabled="page + 1 >= executions.totalPages" @click="page++; refresh()" class="icon-btn icon-btn--sm">
            <Icon name="chevron-right" size="sm"/>
          </button>
        </div>
      </div>
    </div>

    <ExecutionDetail :execution-id="selectedExecutionId" @close="selectedExecutionId = null"/>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'
import { useRoute } from 'vue-router'
import api from '../services/api'
import Icon from '../components/Icon.vue'
import StatusBadge from '../components/StatusBadge.vue'
import ExecutionDetail from '../components/ExecutionDetail.vue'
import { fmt, fmtDuration, isRunning, canRestart } from '../utils/format'
import { domainIcon } from '../utils/domain'
import { usePolling } from '../composables/usePolling'
import { useExecutionActions } from '../composables/useExecutionActions'
import { useUiStore } from '../stores/uiStore'

const STATUS_OPTIONS = [
  { value: '', label: '전체' },
  { value: 'COMPLETED', label: '성공' },
  { value: 'FAILED', label: '실패' },
  { value: 'RUNNING', label: '실행중' },
  { value: 'STOPPED', label: '중지됨' },
]

const route = useRoute()
const ui = useUiStore()

const jobs = ref([])
const executions = ref({ content: [], totalElements: 0, totalPages: 0 })
const page = ref(0)
const filters = ref({
  jobName: route.query.jobName || '',
  status: route.query.status || '',
  from: '',
  to: '',
})
const selectedExecutionId = ref(null)

const runningCount = computed(() => executions.value.content.filter((e) => isRunning(e.status)).length)
const hasFilter = computed(() => Object.values(filters.value).some((v) => v !== ''))

const refresh = async () => {
  try {
    const params = { page: page.value, size: 20 }
    Object.entries(filters.value).forEach(([k, v]) => { if (v) params[k] = v })
    const [execRes, jobsRes] = await Promise.all([
      api.searchExecutions(params),
      jobs.value.length ? Promise.resolve({ data: jobs.value }) : api.listJobs(),
    ])
    executions.value = execRes.data
    jobs.value = jobsRes.data
  } catch (e) {
    ui.toast('error', e.userMessage)
  }
}

const { reschedule } = usePolling(refresh, () => (runningCount.value > 0 ? 5000 : null))

const applyFilters = () => {
  page.value = 0
  refresh().then(reschedule)
}

const clearFilters = () => {
  filters.value = { jobName: '', status: '', from: '', to: '' }
  applyFilters()
}

const actions = useExecutionActions(async () => {
  await refresh()
  reschedule()
})
</script>
